[
  {
    "proposed_id": "side_quest_gold_cap",
    "assert_expr": "quest_type != \"side\" or reward_gold <= 100",
    "rationale": "A side quest must never award more than 100 gold."
  },
  {
    "proposed_id": "main_quest_gold_cap",
    "assert_expr": "quest_type != \"main\" or reward_gold <= 500",
    "rationale": "Main-story quests may award up to 500 gold."
  },
  {
    "proposed_id": "quest_giver_exists",
    "assert_expr": "giver in npc_roster",
    "rationale": "Every quest step's giver must reference an existing NPC in the outpost roster."
  },
  {
    "proposed_id": "quest_final_step_reachable",
    "assert_expr": "final_step_reachable_from_opening == true",
    "rationale": "A quest is only completable when its final step is reachable via next links from the opening step (no orphaned end states)."
  },
  {
    "proposed_id": "drop_entry_item_exists",
    "assert_expr": "drop_item_id in item_catalog",
    "rationale": "Every drop-table entry must point at an item that exists in the item catalog."
  },
  {
    "proposed_id": "drop_probabilities_sum_to_one",
    "assert_expr": "drop_probability_sum == 1.0",
    "rationale": "The drop probabilities within a single drop table must sum to exactly 1.0."
  },
  {
    "proposed_id": "gacha_advertised_rate_accuracy",
    "assert_expr": "advertised_5star_rate - true_5star_rate <= 0.5 and true_5star_rate - advertised_5star_rate <= 0.5",
    "rationale": "The advertised 5-star pull rate must match the true expected pull rate within 0.5 percentage points."
  },
  {
    "proposed_id": "gacha_pity_cap",
    "assert_expr": "pity_pull <= 90",
    "rationale": "A player pulling at the banner's stated rate must reach pity no later than the 90th pull."
  },
  {
    "proposed_id": "xp_curve_monotonic",
    "assert_expr": "xp_to_next_level >= xp_to_next_level_prev",
    "rationale": "The XP-required-to-reach-next-level curve must be monotonically non-decreasing across every level."
  },
  {
    "proposed_id": "economy_faucet_sink_ratio",
    "assert_expr": "total_faucet <= total_sink * 1.2",
    "rationale": "The total currency faucet must not exceed the total currency sink by more than 20%, or the economy inflates."
  }
]

